// 1. Identificamos a la persona desde el Webhook
const webhook = $('Webhook').first().json;
const usernameTelegram = webhook.body.message.from.username;
let persona = (usernameTelegram === "fabotrader") ? "Fabio" : "Laura";

// 2. Agarramos el texto del Agente de IA
let aiRawText = $input.first().json.text;

// --- LIMPIEZA "BULLETPROOF" ---
// A. Eliminamos bloques de código Markdown si existen (```json o ```)
aiRawText = aiRawText.replace(/```json|```/g, "").trim();

let aiData;
try {
  // B. Parseamos el JSON
  const parsed = JSON.parse(aiRawText);

  // C. Si la IA mandó un Array [ ], tomamos el primer elemento. Si no, usamos el objeto.
  aiData = Array.isArray(parsed) ? parsed[0] : parsed;
} catch (e) {
  // Si falla el parseo, devolvemos valores vacíos para no romper el flujo
  aiData = {};
}

// 3. Generamos la Fecha + Hora completa
const ahora = new Date();
const fechaConHora = ahora.toLocaleString('es-AR', {
  day: '2-digit', month: '2-digit', year: 'numeric',
  hour: '2-digit', minute: '2-digit', second: '2-digit',
  hour12: false
});

// 4. RETORNAMOS LA FILA PARA EL SHEET (Asegurando que nada sea undefined)
return {
  Fecha: fechaConHora,
  Persona: persona,
  Tipo: aiData.tipo || "Egreso", // Valor por defecto si falla
  Categoria: aiData.categoria || "Otros",
  Subcategoria: aiData.subcategoria || "",
  Concepto: aiData.concepto || "Gasto registrado",
  Importe: aiData.importe || "0",
  Medio_pago: aiData.medio_pago || "",
  Notas: aiData.notas || ""
};
